patch:
diff --git a/OpenGpxTracker/GPXScaleBar.swift b/OpenGpxTracker/GPXScaleBar.swift
index 169518a..efe18b2 100644
--- a/OpenGpxTracker/GPXScaleBar.swift
+++ b/OpenGpxTracker/GPXScaleBar.swift
@@ -46,6 +46,14 @@ class GPXScaleBar: UIView {
         }
     }

+    /// Optional forced color for all scale bar elements (bar, ticks, labels).
+    /// When set to a non-nil value, the scale bar will use this color instead of system-adaptive colors.
+    public var forcedColor: UIColor? {
+        didSet {
+            applyCurrentColors()
+        }
+    }
+    
     /// The horizontal bar representing the scale distance.
     private let scaleBar = UIView()

@@ -156,22 +164,14 @@ class GPXScaleBar: UIView {
         backgroundColor = .clear

         // Configure scale bar
-        if #available(iOS 13.0, *) {
-            scaleBar.backgroundColor = .label
-        } else {
-            scaleBar.backgroundColor = .black
-        }
+        scaleBar.backgroundColor = currentColor()
         scaleBar.layer.cornerRadius = barHeight / 2
         addSubview(scaleBar)

         // Create ticks (numberOfSegments + 1 for start and end)
         for _ in 0...numberOfSegments {
             let tick = UIView()
-            if #available(iOS 13.0, *) {
-                tick.backgroundColor = .label
-            } else {
-                tick.backgroundColor = .black
-            }
+            tick.backgroundColor = currentColor()
             tick.layer.cornerRadius = tickWidth / 2
             addSubview(tick)
             ticks.append(tick)
@@ -181,11 +181,7 @@ class GPXScaleBar: UIView {
         for _ in 0...numberOfSegments {
             let label = UILabel()
             label.font = .systemFont(ofSize: 11, weight: .medium)
-            if #available(iOS 13.0, *) {
-                label.textColor = .label
-            } else {
-                label.textColor = .black
-            }
+            label.textColor = currentColor()
             label.textAlignment = .center
             addSubview(label)
             labels.append(label)
@@ -193,6 +189,9 @@ class GPXScaleBar: UIView {

         // Set intrinsic size
         translatesAutoresizingMaskIntoConstraints = false
+        
+        // Apply initial colors respecting forcedColor if set
+        applyCurrentColors()
     }

     /// Sets up notification observer for map region changes.
@@ -207,6 +206,20 @@ class GPXScaleBar: UIView {
         )
     }

+    /// Returns the appropriate color depending on whether a forcedColor is set
+    private func currentColor() -> UIColor {
+        if let forcedColor = forcedColor { return forcedColor }
+        if #available(iOS 13.0, *) { return .label } else { return .black }
+    }
+
+    /// Applies the current color to all subviews (bar, ticks, labels)
+    private func applyCurrentColors() {
+        let color = currentColor()
+        scaleBar.backgroundColor = color
+        ticks.forEach { $0.backgroundColor = color }
+        labels.forEach { $0.textColor = color }
+    }
+    
     /// Handles map region change notifications.
     ///
     /// This method is called automatically when the map's visible region changes.
@@ -645,3 +658,4 @@ class SettingsViewController: UIViewController {
     }
 }
 */
+
diff --git a/OpenGpxTracker/GPXTileServer.swift b/OpenGpxTracker/GPXTileServer.swift
index 247bf14..3aed2a8 100644
--- a/OpenGpxTracker/GPXTileServer.swift
+++ b/OpenGpxTracker/GPXTileServer.swift
@@ -159,8 +159,20 @@ enum GPXTileServer: Int {
         }
     }

-    var needForceDarkMode: Bool {
-        return self == .appleSatellite
+    /// Defines the color mode for the tile server
+    enum GPXTileServerColorMode {
+        case lightMode
+        case system
+        case darkMode
+    }
+    
+    /// Returns the color mode for the tile server
+    var colorMode: GPXTileServerColorMode {
+        switch self {
+        case .apple: return .system
+        case .appleSatellite: return .darkMode
+        case .cartoDB, .cartoDBRetina, .openTopoMap, .openSeaMap, .openStreetMap: return .lightMode
+        }
     }

     /// Returns the number of tile servers currently defined
diff --git a/OpenGpxTracker/ViewController.swift b/OpenGpxTracker/ViewController.swift
index fe592ce..564219c 100644
--- a/OpenGpxTracker/ViewController.swift
+++ b/OpenGpxTracker/ViewController.swift
@@ -805,6 +805,8 @@ class ViewController: UIViewController, UIGestureRecognizerDelegate {
 				constant: -36
 			)
 		])
+        
+        textColorAdaptations()
 	}

     @available(iOS 11, *)
@@ -1303,12 +1305,29 @@ class ViewController: UIViewController, UIGestureRecognizerDelegate {

     /// force dark mode (i.e. white text, if map content is known to be dark)
     func textColorAdaptations() {
-        let needForceDarkMode = self.map.tileServer.needForceDarkMode
-        self.signalAccuracyLabel.textColor = needForceDarkMode ? .white : nil
-        self.timeLabel.textColor = needForceDarkMode ? .white : nil
-        self.speedLabel.textColor = needForceDarkMode ? .white : nil
-        self.totalTrackedDistanceLabel.textColor = needForceDarkMode ? .white : nil
-        self.currentSegmentDistanceLabel.textColor = needForceDarkMode ? .white : nil
+        print("-- textColorAdaptation:: Tile server mode: \(self.map.tileServer.colorMode)")
+        let colorMode = self.map.tileServer.colorMode
+        
+        let color: UIColor?
+        switch colorMode {
+        case .lightMode:
+            color = .black
+        case .darkMode:
+            color = .white
+        case .system:
+            color = nil
+        }
+        
+        self.signalAccuracyLabel.textColor = color
+        self.timeLabel.textColor = color
+        self.speedLabel.textColor = color
+        self.totalTrackedDistanceLabel.textColor = color
+        self.currentSegmentDistanceLabel.textColor = color
+        
+        // Apply the same forced color behavior to the scale bar
+        if let scaleBar = self.map.scaleBar {
+            scaleBar.forcedColor = color
+        }
     }

 }
@@ -1532,3 +1551,4 @@ extension Notification.Name {
 }

 // swiftlint:enable line_length
+
